export const getWhatsappSentMessagesById = <ThrowOnError extends boolean = false>(options: Options<GetWhatsappSentMessagesByIdData, ThrowOnError>) => (options.client ?? client).get<GetWhatsappSentMessagesByIdResponses, GetWhatsappSentMessagesByIdErrors, ThrowOnError>({
    security: [{ name: 'X-AUTH-TOKEN', type: 'apiKey' }],
    url: '/whatsapp/sent_messages/{id}',
    ...options
});
